arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$BRANCH = "copilot/39-demo-polish-and-readme"
$PR_NUMBER = "24"

# Wait for CCA to finish
Write-Host "Waiting for CCA to complete..."
$TIMEOUT = 1200
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    $runs = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion `
        --jq '.[] | {id: .databaseId, name: .name, status: .status, conclusion: .conclusion}' | ConvertFrom-Json

    $ccaRun = $runs | Where-Object { $_.name -like "*Copilot*" }

    if ($ccaRun) {
        Write-Host "[${ELAPSED}s] CCA status: $($ccaRun.status) / conclusion: $($ccaRun.conclusion)"
        if ($ccaRun.status -eq "completed") {
            Write-Host "CCA completed with: $($ccaRun.conclusion)"
            break
        }
    } else {
        # Check for action_required runs
        $actionRuns = gh run list -R $REPO --branch $BRANCH --status action_required --json databaseId,name `
            --jq '.[].databaseId' 2>$null
        if ($actionRuns) {
            Write-Host "Found action_required runs: $actionRuns"
            break
        }
        Write-Host "[${ELAPSED}s] No CCA run found yet, waiting..."
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

Write-Host "Done polling. Elapsed: ${ELAPSED}s"

