arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$BRANCH = "copilot/39-demo-polish-and-readme"
$PR_NUMBER = "24"
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

Write-Host "Polling for workflow runs (action_required or in-progress)..."

while ($ELAPSED -lt $TIMEOUT) {
    # Check action_required
    $actionReq = gh api "/repos/$REPO/actions/runs?branch=$BRANCH&status=action_required" `
        --jq '.workflow_runs[] | .id' 2>$null

    # Check in_progress
    $inProgress = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status `
        --jq '.[] | select(.status == "in_progress" or .status == "queued") | {id: .databaseId, name: .name, status: .status}' 2>$null

    if ($actionReq) {
        Write-Host "[${ELAPSED}s] Found action_required runs: $actionReq"
        # Approve them
        foreach ($runId in $actionReq) {
            Write-Host "  Approving run $runId..."
            gh run rerun $runId -R $REPO 2>&1
        }
    }

    if ($inProgress) {
        Write-Host "[${ELAPSED}s] In-progress runs: $inProgress"
    } else {
        # Check if all completed
        $all = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion `
            --jq '.[] | select(.status != "completed") | .databaseId' 2>$null
        if (-not $all -and $ELAPSED -gt 60) {
            Write-Host "[${ELAPSED}s] No pending runs. Checking final PR check status..."
            gh pr checks $PR_NUMBER -R $REPO 2>&1
            break
        }
        Write-Host "[${ELAPSED}s] No active runs yet..."
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

Write-Host "Done. Elapsed: ${ELAPSED}s"

